    /**
     * @method
     * @name extended#fetchTickers
     * @description fetches price tickers for multiple markets, statistical information calculated over the past 24 hours for all markets
     * @see https://api.docs.extended.exchange/#get-markets
     * @param {string[]} [symbols] unified symbols of the markets to fetch the ticker for, all market tickers are returned if not assigned
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a dictionary of [ticker structures]{@link https://docs.ccxt.com/?id=ticker-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTickers(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            symbols = this.marketSymbols(symbols);
            Object request = new java.util.HashMap<String, Object>() {{}};
            if (Helpers.isTrue(!Helpers.isEqual(symbols, null)))
            {
                Object marketIds = new java.util.ArrayList<Object>(java.util.Arrays.asList());
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(symbols)); i++)
                {
                    Object market = this.market(Helpers.GetValue(symbols, i));
                    ((java.util.List<Object>)marketIds).add(Helpers.GetValue(market, "id"));
                }
                Helpers.addElementToObject(request, "market", marketIds);
            }
            Object response = (this.v1PublicGetInfoMarkets(this.extend(request, parameters))).join();
            //
            //     {
            //       "status": "OK",
            //       "data": [
            //         {
            //           "name": "BTC-USD",
            //           "assetName": "BTC",
            //           "collateralAssetName": "USD",
            //           "marketStats": {
            //             "dailyVolume": "231016077.512960",
            //             ...
            //           },
            //           ...
            //         }
            //       ]
            //     }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object tickers = new java.util.HashMap<String, Object>() {{}};
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
            {
                Object marketData = Helpers.GetValue(data, i);
                Object marketId = this.safeString(marketData, "name");
                Object market = this.safeMarket(marketId);
                Object stats = this.safeDict(marketData, "marketStats", new java.util.HashMap<String, Object>() {{}});
                Object ticker = this.parseTicker(stats, market);
                Object symbol = Helpers.GetValue(ticker, "symbol");
                if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
                {
                    Helpers.addElementToObject(tickers, symbol, ticker);
                }
            }
            return this.filterByArrayTickers(tickers, "symbol", symbols);
        });

    }

    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        //     {
        //       "dailyVolume": "231216165.666600",
        //       "dailyVolumeBase": "3027.36710",
        //       "dailyPriceChange": "181",
        //       "dailyPriceChangePercentage": "0.0024",
        //       "dailyLow": "75635",
        //       "dailyHigh": "77399",
        //       "lastPrice": "77026",
        //       "askPrice": "77026",
        //       "bidPrice": "77025",
        //       "markPrice": "77006.091897999984",
        //       "indexPrice": "77050.739529925005",
        //       "fundingRate": "0.000012",
        //       "nextFundingRate": 1777446000000,
        //       "openInterest": "114851569.088316",
        //       "openInterestBase": "1491.33012",
        //       "deleverageLevels": {
        //         "shortPositions": [
        //           { "level": 1, "rankingLowerBound": "-784.2884" },
        //           { "level": 2, "rankingLowerBound": "-2.1078" },
        //           { "level": 3, "rankingLowerBound": "-0.8754" },
        //           { "level": 4, "rankingLowerBound": "0.0000" }
        //         ],
        //         "longPositions": [
        //           { "level": 1, "rankingLowerBound": "-47747.2010" },
        //           { "level": 2, "rankingLowerBound": "-0.0131" },
        //           { "level": 3, "rankingLowerBound": "0.0019" },
        //           { "level": 4, "rankingLowerBound": "0.0032" }
        //         ]
        //       }
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object symbol = this.safeSymbol(null, market);
        Object last = this.safeNumber(ticker, "lastPrice");
        Object percentageRaw = this.safeString(ticker, "dailyPriceChangePercentage");
        Object percentage = ((Helpers.isTrue((!Helpers.isEqual(percentageRaw, null))))) ? Precise.stringMul(percentageRaw, "100") : null;
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", null );
            put( "datetime", null );
            put( "high", ExtendedCore.this.safeNumber(ticker, "dailyHigh") );
            put( "low", ExtendedCore.this.safeNumber(ticker, "dailyLow") );
            put( "bid", ExtendedCore.this.safeNumber(ticker, "bidPrice") );
            put( "bidVolume", null );
            put( "ask", ExtendedCore.this.safeNumber(ticker, "askPrice") );
            put( "askVolume", null );
            put( "vwap", null );
            put( "open", null );
            put( "close", last );
            put( "last", last );
            put( "previousClose", null );
            put( "change", ExtendedCore.this.safeNumber(ticker, "dailyPriceChange") );
            put( "percentage", percentage );
            put( "average", null );
            put( "baseVolume", ExtendedCore.this.safeNumber(ticker, "dailyVolumeBase") );
            put( "quoteVolume", ExtendedCore.this.safeNumber(ticker, "dailyVolume") );
            put( "markPrice", ExtendedCore.this.safeNumber(ticker, "markPrice") );
            put( "indexPrice", ExtendedCore.this.safeNumber(ticker, "indexPrice") );
            put( "info", ticker );
        }}, market);
    }

