    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        //     {
        //         "id": "1951255127004282880",
        //         "type": "TRANSFER",
        //         "status": "COMPLETED",
        //         "amount": "-3.0000000000000000",
        //         "fee": "0",
        //         "asset": 1,
        //         "time": 1754050449502,
        //         "accountId": 100009,
        //         "counterpartyAccountId": 100023
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(transaction, "time");
        Object assetId = this.safeString(transaction, "asset");
        Object code = this.getExtendedCurrencyCodeById(assetId, currency);
        Object amountString = this.safeString(transaction, "amount");
        Object amount = ((Helpers.isTrue((Helpers.isEqual(amountString, null))))) ? null : this.parseNumber(Precise.stringAbs(amountString));
        Object fee = null;
        Object feeCost = this.safeString(transaction, "fee");
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "currency", code );
                put( "cost", ExtendedCore.this.parseNumber(Precise.stringAbs(finalFeeCost)) );
            }};
        }
        Object transactionType = this.parseTransactionType(this.safeString(transaction, "type"));
        Object network = this.safeString(transaction, "chain");
        final Object finalTransactionType = transactionType;
        final Object finalFee = fee;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", ExtendedCore.this.safeString(transaction, "id") );
            put( "txid", ExtendedCore.this.safeString(transaction, "transactionHash") );
            put( "timestamp", timestamp );
            put( "datetime", ExtendedCore.this.iso8601(timestamp) );
            put( "address", null );
            put( "addressFrom", null );
            put( "addressTo", null );
            put( "tag", null );
            put( "tagFrom", null );
            put( "tagTo", null );
            put( "type", finalTransactionType );
            put( "amount", amount );
            put( "currency", code );
            put( "status", ExtendedCore.this.parseTransactionStatus(ExtendedCore.this.safeString(transaction, "status")) );
            put( "updated", timestamp );
            put( "fee", finalFee );
            put( "network", network );
            put( "comment", null );
            put( "internal", (Helpers.isEqual(finalTransactionType, "transfer")) );
        }};
    }

